import sys
from collections import deque, defaultdict
import bisect

def solve_grid(input_data):
    original_width = int(input_data[0])
    original_height = int(input_data[1])
    max_loops = int(input_data[2])

    grid_str = input_data[3:]

    # Bounding Box
    min_x, max_x = original_width, 0
    min_y, max_y = original_height, 0

    for y in range(original_height):
        for x in range(original_width):
            if grid_str[y][x] != '#':
                if x < min_x: min_x = x
                if x > max_x: max_x = x
                if y < min_y: min_y = y
                if y > max_y: max_y = y

    min_x = max(0, min_x - 1)
    max_x = min(original_width - 1, max_x + 1)
    min_y = max(0, min_y - 1)
    max_y = min(original_height - 1, max_y + 1)

    width = max_x - min_x + 1
    height = max_y - min_y + 1
    grid_str = [row[min_x:max_x+1] for row in grid_str[min_y:max_y+1]]
    size = width * height

    walls = [False] * size
    door_mask = [0] * size
    switch_mask = [0] * size
    S_pos = E_pos = -1

    switch_positions = {}

    for y in range(height):
        for x in range(width):
            pos = y * width + x
            c = grid_str[y][x]
            if c == '#': walls[pos] = True
            elif c == 'S': S_pos = pos
            elif c == 'E': E_pos = pos
            elif 'a' <= c <= 'z': 
                bit = ord(c) - ord('a')
                switch_mask[pos] = 1 << bit
                switch_positions[bit] = pos
            elif 'A' <= c <= 'Z': 
                door_mask[pos] = 1 << (ord(c) - ord('A'))

    # Adaptive beam
    if size < 150: 
        pareto_limit = 20
        final_pareto_limit = 40
        base_K_limit = 8
        last_K_limit = 2
    else:          
        pareto_limit = 10
        final_pareto_limit = 20
        base_K_limit = 3
        last_K_limit = 1

    moves = [(0, 'W', 0), (1, 'U', -width), (2, 'R', 1), (3, 'L', -1), (4, 'D', width)]

    adj_all_mapped = [[] for _ in range(size)]
    for pos in range(size):
        if walls[pos]: continue
        for m_val, m_char, delta in moves:
            npos = pos + delta
            if m_char == 'L' and pos % width == 0: continue
            if m_char == 'R' and (pos + 1) % width == 0: continue
            if 0 <= npos < size and not walls[npos]:
                adj_all_mapped[pos].append((npos, m_val))

    # Check for deadlock
    reachable_closure = 0
    changed = True
    while changed:
        changed = False
        q = deque([S_pos])
        vis = bytearray(size)
        vis[S_pos] = 1
        while q:
            p = q.popleft()
            for np, m_val in adj_all_mapped[p]:
                if m_val == 0: continue 
                req = door_mask[np]
                if req and not (reachable_closure & req): continue
                if not vis[np]:
                    vis[np] = 1
                    q.append(np)

        for bit, pos in list(switch_positions.items()):
            if not (reachable_closure & (1 << bit)) and vis[pos]:
                reachable_closure |= (1 << bit)
                changed = True

    valid_switch_positions = {}
    for bit, pos in switch_positions.items():
        if (1 << bit) & reachable_closure:
            valid_switch_positions[bit] = pos
        else:
            switch_mask[pos] = 0
    switch_positions = valid_switch_positions

    memo_dist = {}
    def get_distances(targets_tuple, open_doors):
        state = (targets_tuple, open_doors)
        if state in memo_dist: return memo_dist[state]

        dist = [9999] * size
        q = deque(targets_tuple)
        for t in targets_tuple:
            dist[t] = 0

        while q:
            pos = q.popleft()
            req = door_mask[pos]
            if req and not (open_doors & req): continue

            d = dist[pos] + 1
            for npos, m_val in adj_all_mapped[pos]:
                if m_val == 0: continue 
                if dist[npos] == 9999:
                    dist[npos] = d
                    q.append(npos)

        memo_dist[state] = dist
        return dist

    memo_S_to_any = {}
    bfs_counter = [0]

    def get_dist_S_to_any(targets_tuple, open_doors):
        state = (targets_tuple, open_doors)
        if state in memo_S_to_any: return memo_S_to_any[state]

        if bfs_counter[0] > 2500:
            return 0
        bfs_counter[0] += 1

        is_target = bytearray(size)
        for t in targets_tuple:
            if t == S_pos: return 0
            is_target[t] = 1

        visited = bytearray(size)
        visited[S_pos] = 1
        q = deque([S_pos])
        d = 0

        while q:
            d += 1
            for _ in range(len(q)):
                pos = q.popleft()
                for npos, m_val in adj_all_mapped[pos]:
                    if m_val == 0: continue
                    if not visited[npos]:
                        req = door_mask[npos]
                        if req and not (open_doors & req): continue
                        if is_target[npos]:
                            memo_S_to_any[state] = d
                            return d
                        visited[npos] = 1
                        q.append(npos)

        memo_S_to_any[state] = 9999
        return 9999

    def get_opt_dist(targets_tuple):
        dist = [9999] * size
        q = deque(targets_tuple)
        for t in targets_tuple: dist[t] = 0
        while q:
            pos = q.popleft()
            d = dist[pos] + 1
            for npos, m_val in adj_all_mapped[pos]:
                if m_val == 0: continue 
                if dist[npos] == 9999:
                    dist[npos] = d
                    q.append(npos)
        return dist

    dist_to_E_opt = get_opt_dist((E_pos,))

    all_doors_open = (1 << 26) - 1
    dist_from_switch = {}
    for i, s_pos in switch_positions.items():
        dist_from_switch[i] = get_distances((s_pos,), all_doors_open)

    reachable_sw = [[0] * 205 for _ in range(size)]
    for pos in range(size):
        if walls[pos]: continue
        for tl in range(205):
            mask = 0
            for i in switch_positions:
                if dist_from_switch[i][pos] <= tl:
                    mask |= (1 << i)
            reachable_sw[pos][tl] = mask

    min_T = get_distances((E_pos,), all_doors_open)[S_pos]
    if min_T == 9999: return "No solution."

    def get_positions(path_tuple):
        pos = S_pos
        res = [pos]
        for m_val in path_tuple:
            if m_val == 0: pos += 0
            elif m_val == 1: pos -= width
            elif m_val == 2: pos += 1
            elif m_val == 3: pos -= 1
            elif m_val == 4: pos += width
            res.append(pos)
        return res

    global_dist_cache = {}

    def solve_sequence(loop_idx, open_doors, ghost_paths, T, N):
        if loop_idx == N: return []
        is_last_loop = (loop_idx == N - 1)

        unpressed = tuple(p for p in switch_positions.values() if not (open_doors & switch_mask[p]))
        dist_E_open = get_distances((E_pos,), open_doors)

        # Airbag
        if is_last_loop:
            if dist_E_open[S_pos] > T: return None
        else:
            if not unpressed:
                if dist_E_open[S_pos] > T: return None
            else:
                if get_distances(unpressed, open_doors)[S_pos] > T:
                    if size >= 150 or dist_E_open[S_pos] > T:
                        return None

        if not is_last_loop:
            if unpressed:
                dist_unpressed_open = get_distances(unpressed, open_doors)
            else:
                dist_unpressed_open = [9999] * size

        ghost_occ = [[False] * size for _ in range(T + 1)]
        for g_pos_list in ghost_paths:
            for t, g_pos in enumerate(g_pos_list):
                ghost_occ[t][g_pos] = True

        active = {(S_pos, 0): [()]}
        K_limit = base_K_limit if not is_last_loop else last_K_limit

        for t in range(T):
            next_active = {}
            g_t1 = ghost_occ[t+1]
            time_left = T - t       
            rem_time = time_left - 1 

            for (pos, sw), paths in active.items():

                future_doors = open_doors | sw | reachable_sw[pos][time_left]
                doomed = False

                if is_last_loop:
                    if dist_to_E_opt[pos] > time_left:
                        doomed = True
                else:
                    cache_key = (future_doors, loop_idx == N - 2)
                    if cache_key in global_dist_cache:
                        dist_req = global_dist_cache[cache_key]
                    else:
                        if loop_idx == N - 2:
                            dist_req = get_dist_S_to_any((E_pos,), future_doors)
                        else:
                            unpressed_future = tuple(p for i, p in switch_positions.items() if not (future_doors & (1 << i)))
                            if unpressed_future:
                                dist_req = get_dist_S_to_any(unpressed_future, future_doors)
                            else:
                                dist_req = 0
                        global_dist_cache[cache_key] = dist_req

                    if dist_req > T:
                        # Airbag du futur
                        if size < 150 and get_dist_S_to_any((E_pos,), future_doors) <= T:
                            pass
                        else:
                            doomed = True

                if doomed: continue 

                valid_moves = [(pos, 0)] if (is_last_loop and pos == E_pos) else adj_all_mapped[pos]

                for npos, m_val in valid_moves:
                    req = door_mask[npos]
                    if req and not (open_doors & req): continue
                    if npos != S_pos and g_t1[npos]: continue

                    if is_last_loop:
                        if dist_E_open[npos] > rem_time: continue 
                        nsw = 0
                    else:
                        if sw == 0:
                            if dist_unpressed_open[npos] > rem_time:
                                # Tolerance
                                if size < 150 and dist_E_open[npos] <= rem_time:
                                    pass
                                else:
                                    continue 
                        nsw = sw | switch_mask[npos]

                    state = (npos, nsw)
                    lst = next_active.get(state)
                    if lst is None:
                        next_active[state] = lst = []

                    for p in paths:
                        n_path = p + (m_val,)
                        if n_path not in lst:
                            bisect.insort(lst, n_path) 
                            if len(lst) > K_limit:
                                lst.pop()

            active = {}
            pos_groups = defaultdict(list)
            for state, paths in next_active.items():
                pos_groups[state[0]].append((state[1], paths))

            for pos, sw_list in pos_groups.items():
                if len(sw_list) > pareto_limit:
                    list_bits = sorted(sw_list, key=lambda x: (-x[0].bit_count(), x[1][0]))
                    list_paths = sorted(sw_list, key=lambda x: x[1][0])

                    combined = {sw: paths for sw, paths in list_bits[:pareto_limit]}
                    for sw, paths in list_paths[:pareto_limit]:
                        if sw not in combined or paths[0] < combined[sw][0]:
                            combined[sw] = paths
                    sw_list = list(combined.items())

                sw_list.sort(key=lambda x: (-x[0].bit_count(), x[1][0]))
                valid_for_pos = []

                for sw1, paths1 in sw_list:
                    dominated = False
                    for sw2, paths2 in valid_for_pos:
                        if (sw1 & sw2) == sw1 and paths2[0] <= paths1[0]:
                            dominated = True
                            break

                    if not dominated:
                        valid_for_pos.append((sw1, paths1))
                        active[(pos, sw1)] = paths1

            if not active: return None

        if is_last_loop:
            final_paths = active.get((E_pos, 0))
            if final_paths:
                return [final_paths[0]]
            return None
        else:
            grouped_items = defaultdict(list)
            for (pos, sw), paths in active.items():
                if sw > 0:
                    grouped_items[sw].extend(paths)

            # No switch found
            if not grouped_items and size < 150:
                if (E_pos, 0) in active:
                    grouped_items[0] = active[(E_pos, 0)]
                elif active:
                    for pos, sw in sorted(active.keys(), key=lambda x: (x[0]!=E_pos, x[0]!=S_pos)):
                        grouped_items[0] = active[(pos, sw)]
                        break

            if not grouped_items: return None

            grouped_list = []
            for sw, lst in grouped_items.items():
                lst.sort()
                grouped_list.append((sw, lst))

            if len(grouped_list) > final_pareto_limit:
                list_bits = sorted(grouped_list, key=lambda x: (-x[0].bit_count(), x[1][0]))
                list_paths = sorted(grouped_list, key=lambda x: x[1][0])

                combined = {sw: lst for sw, lst in list_bits[:final_pareto_limit]}
                for sw, lst in list_paths[:final_pareto_limit]:
                    if sw not in combined or lst[0] < combined[sw][0]:
                        combined[sw] = lst
                grouped_list = list(combined.items())

            grouped_list.sort(key=lambda x: (-x[0].bit_count(), x[1][0]))
            valid_cands = []
            pareto_cands = []

            for sw1, lst1 in grouped_list:
                dominated = False
                for sw2, lst2 in valid_cands:
                    if (sw1 & sw2) == sw1 and lst2[0] <= lst1[0]:
                        dominated = True
                        break

                if not dominated:
                    valid_cands.append((sw1, lst1))
                    for p in lst1[:K_limit]:
                        pareto_cands.append((p, sw1))

            pareto_cands.sort(key=lambda x: x[0])

            for path, sw in pareto_cands:
                next_open = open_doors | sw
                new_ghost = get_positions(path)
                res = solve_sequence(loop_idx + 1, next_open, ghost_paths + [new_ghost], T, N)
                if res is not None:
                    return [path] + res
            return None

    for T in range(min_T, 200):
        for N in range(1, max_loops + 1):
            result = solve_sequence(0, 0, [], T, N)

            if result:
                while all(len(path) > 1 and path[0] == 0 for path in result):
                    result = [path[1:] for path in result]

                chars = {0: 'W', 1: 'U', 2: 'R', 3: 'L', 4: 'D'}
                formatted_res = []
                for path in result:
                    formatted_res.append(" ".join(chars[m] for m in path))
                return "\n".join(formatted_res)

    return "No solution."

if __name__ == '__main__':
    input_data = sys.stdin.read().split()
    if input_data:
        print(solve_grid(input_data), flush=True)

data.constraints:
- {{3}} ≤ [[width]] ≤ {{30}}
- {{3}} ≤ [[height]] ≤ {{20}}
- {{1}} ≤ [[max_loops]] ≤ {{5}}
- Every side of the grid is a wall ({{#}}).
- The grid contains exactly one {{S}} and one {{E}}.
- Each switch letter and each door letter appears at most once
- Every door is placed so that it blocks all possible routes through its location unless it is opened; it cannot be bypassed by walking around it.
- Every test case is guaranteed to have a solution.
